parameters.jsonBody:
={
  "query": "query GetTranscript($id: String!) { transcript(id: $id) { id title date duration participants video_url audio_url transcript_url summary { keywords overview } } }",
  "variables": {
    "id": "{{ $json.meetingId }}"
  }
}

parameters.jsCode:
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const t = response?.data?.transcript;
if (!t || !t.id) throw new Error('Transcript not found for meetingId: ' + config.meetingId);

const videoUrl = t.video_url || '';
const audioUrl = t.audio_url || '';
const mediaUrl = videoUrl || audioUrl;

if (!mediaUrl) {
  throw new Error(
    'No video_url or audio_url available for meeting: ' + (t.title || t.id) +
    '. Make sure Fireflies bot joined and recorded the meeting.'
  );
}

const meetingDate = t.date
  ? new Date(t.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

const keywords = (t.summary?.keywords || []).slice(0, 8).join(', ');
const overview = (t.summary?.overview || '').substring(0, 400);

return [{
  json: {
    meetingId: t.id,
    meetingTitle: t.title || 'Untitled Meeting',
    meetingDate,
    durationMin: Math.round((t.duration || 0) / 60),
    participants: (t.participants || []).join(', ') || 'Unknown',
    mediaUrl,
    isVideo: !!videoUrl,
    transcriptUrl: t.transcript_url || '',
    keywords,
    overview,
    wayinVideoApiKey: config.wayinVideoApiKey,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    slackChannel: config.slackChannel,
    findMomentsQuery: config.findMomentsQuery,
    maxClips: parseInt(config.maxClips) || 3
  }
}];

const response = $input.first().json;
const prev = $('4. Code — Extract Video URL').item.json;

const projectId = response?.data?.id;
if (!projectId) throw new Error('WayinVideo did not return a project ID. Check API key and video URL.');

return [{
  json: {
    projectId,
    status: response.data.status || 'CREATED',
    meetingTitle: prev.meetingTitle,
    meetingDate: prev.meetingDate,
    durationMin: prev.durationMin,
    participants: prev.participants,
    mediaUrl: prev.mediaUrl,
    transcriptUrl: prev.transcriptUrl,
    keywords: prev.keywords,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    slackChannel: prev.slackChannel,
    findMomentsQuery: prev.findMomentsQuery,
    maxClips: prev.maxClips,
    pollCount: 0
  }
}];

const pollResponse = $input.first().json;
const prev = $('6. Code — Save Project ID').item.json;

const status = pollResponse?.data?.status || 'UNKNOWN';
const pollCount = (prev.pollCount || 0) + 1;

if (pollCount >= 20 && status !== 'SUCCEEDED') {
  throw new Error('WayinVideo timeout after 20 polls (~15 min). Project: ' + prev.projectId);
}

if (status === 'FAILED') {
  throw new Error('WayinVideo processing failed: ' + (pollResponse?.data?.error_message || 'Unknown error'));
}

return [{
  json: {
    projectId: prev.projectId,
    status,
    clips: pollResponse?.data?.clips || [],
    pollCount,
    isReady: status === 'SUCCEEDED',
    meetingTitle: prev.meetingTitle,
    meetingDate: prev.meetingDate,
    durationMin: prev.durationMin,
    participants: prev.participants,
    transcriptUrl: prev.transcriptUrl,
    keywords: prev.keywords,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    slackChannel: prev.slackChannel,
    findMomentsQuery: prev.findMomentsQuery,
    maxClips: prev.maxClips
  }
}];

const data = $input.first().json;
const clips = data.clips || [];

if (clips.length === 0) {
  throw new Error('WayinVideo returned no clips. The query may not match any moments in this video.');
}

const topClips = [...clips]
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, data.maxClips || 3);

const msToTime = (ms) => {
  const totalSecs = Math.floor((ms || 0) / 1000);
  const mins = Math.floor(totalSecs / 60);
  const secs = totalSecs % 60;
  return mins + ':' + String(secs).padStart(2, '0');
};

const loggedAt = new Date().toISOString().replace('T', ' ').substring(0, 16);

const sheetRows = topClips.map((clip, i) => ({
  date: data.meetingDate,
  meetingTitle: data.meetingTitle,
  clipNum: (i + 1),
  clipTitle: clip.title || 'Untitled Clip',
  startTime: msToTime(clip.begin_ms),
  endTime: msToTime(clip.end_ms),
  durationSec: Math.round(((clip.end_ms || 0) - (clip.begin_ms || 0)) / 1000),
  score: clip.score || 0,
  tags: (clip.tags || []).join(', '),
  description: (clip.desc || '').substring(0, 200),
  loggedAt,
  sheetId: data.sheetId,
  sheetName: data.sheetName
}));

let clipLines = '';
topClips.forEach((clip, i) => {
  const duration = Math.round(((clip.end_ms || 0) - (clip.begin_ms || 0)) / 1000);
  clipLines +=
    (i + 1) + '. *' + (clip.title || 'Clip ' + (i + 1)) + '* — ' +
    msToTime(clip.begin_ms) + ' to ' + msToTime(clip.end_ms) +
    ' (' + duration + 's) | Score: ' + (clip.score || 0) + '/100\n' +
    '   ' + (clip.desc || '').substring(0, 100) + '\n';
});

const slackMessage =
  '*New Sales Training Clips*\n\n' +
  '*Meeting:* ' + data.meetingTitle + '\n' +
  '*Date:* ' + data.meetingDate + ' | *Duration:* ' + data.durationMin + ' min\n' +
  '*Query:* _' + data.findMomentsQuery + '_\n' +
  '*Clips Found:* ' + topClips.length + '\n\n' +
  clipLines +
  '\n_Full recording: ' + (data.transcriptUrl || 'See Fireflies') + '_';

return [{
  json: {
    sheetRows,
    slackMessage,
    slackChannel: data.slackChannel,
    totalClips: topClips.length
  }
}];

const data = $input.first().json;
const rows = data.sheetRows || [];

return rows.map((row, i) => ({
  json: {
    ...row,
    isLastRow: i === rows.length - 1,
    slackMessage: data.slackMessage,
    slackChannel: data.slackChannel
  }
}));
